import pandas as pd

# 从已获取并暂存的企业2426小时排放记录计算统计量；不覆盖最终输出变量
ap_emission_df_2426_window_source = df_company_2426_emission_raw

ap_start_2426 = pd.to_datetime(company_2426_start_ts)
ap_end_inclusive_2426 = pd.to_datetime(company_2426_end_ts_inclusive)

ap_df_2426 = ap_emission_df_2426_window_source.copy()
if "timestamp" in ap_df_2426.columns:
    ap_df_2426["timestamp"] = pd.to_datetime(ap_df_2426["timestamp"])
    ap_df_2426_window = ap_df_2426[(ap_df_2426["timestamp"] >= ap_start_2426) & (ap_df_2426["timestamp"] <= ap_end_inclusive_2426)]
else:
    ap_df_2426_window = ap_df_2426

if "company_id" in ap_df_2426_window.columns:
    ap_df_2426_window = ap_df_2426_window[ap_df_2426_window["company_id"] == company_id_2426]

ap_company_2426_emission_window_row_count = int(len(ap_df_2426_window))
ap_company_2426_exhaust_gas_nonnull_count = int(ap_df_2426_window["exhaust_gas"].notna().sum()) if "exhaust_gas" in ap_df_2426_window.columns else 0
ap_company_2426_nox_nonnull_count = int(ap_df_2426_window["nox"].notna().sum()) if "nox" in ap_df_2426_window.columns else 0

ap_company_2426_emission_calc_findings = {
    "company_id": int(company_id_2426),
    "start_time": str(ap_start_2426),
    "end_time_inclusive": str(ap_end_inclusive_2426),
    "row_count": ap_company_2426_emission_window_row_count,
    "exhaust_gas_nonnull_count": ap_company_2426_exhaust_gas_nonnull_count,
    "nox_nonnull_count": ap_company_2426_nox_nonnull_count,
    "status": "computed" if ap_company_2426_emission_window_row_count > 0 else "no_rows_in_staged_emission_records"
}

if ap_company_2426_emission_window_row_count > 0 and ap_company_2426_exhaust_gas_nonnull_count > 0:
    ap_company_2426_total_flue_gas_sum = float(ap_df_2426_window["exhaust_gas"].sum(skipna=True))
    ap_company_2426_peak_flue_gas_max = float(ap_df_2426_window["exhaust_gas"].max(skipna=True))
    ap_company_2426_emission_calc_findings.update({
        "total_flue_gas_candidate": ap_company_2426_total_flue_gas_sum,
        "peak_flue_gas_candidate": ap_company_2426_peak_flue_gas_max
    })
else:
    ap_company_2426_emission_calc_findings.update({
        "total_flue_gas_candidate": None,
        "peak_flue_gas_candidate": None,
        "flue_gas_note": "no non-null exhaust_gas readings available"
    })

if ap_company_2426_emission_window_row_count > 0 and ap_company_2426_nox_nonnull_count > 0:
    ap_company_2426_total_nox_sum = float(ap_df_2426_window["nox"].sum(skipna=True))
    ap_company_2426_emission_calc_findings["total_nox_candidate"] = ap_company_2426_total_nox_sum
else:
    ap_company_2426_emission_calc_findings.update({
        "total_nox_candidate": None,
        "nox_note": "no non-null nox readings available"
    })

print({
    "company_id": ap_company_2426_emission_calc_findings["company_id"],
    "time_window": f"{ap_company_2426_emission_calc_findings['start_time']} 至 {ap_company_2426_emission_calc_findings['end_time_inclusive']}（含结束时刻）",
    "records_used": ap_company_2426_emission_window_row_count,
    "flue_gas_nonnull_hours": ap_company_2426_exhaust_gas_nonnull_count,
    "nox_nonnull_hours": ap_company_2426_nox_nonnull_count,
    "total_flue_gas_candidate": ap_company_2426_emission_calc_findings["total_flue_gas_candidate"],
    "peak_flue_gas_candidate": ap_company_2426_emission_calc_findings["peak_flue_gas_candidate"],
    "total_nox_candidate": ap_company_2426_emission_calc_findings["total_nox_candidate"]
})
